+/**
+ * Analytics route handlers — connect HTTP endpoints to the AnalyticsService.
+ *
+ * Each handler validates input, calls the appropriate service method,
+ * and returns a typed response with the correct status code.
+ *
+ * Routes:
+ * - GET /analytics/dashboard   → getDashboard
+ * - GET /analytics/orders      → getOrderMetrics
+ * - GET /analytics/users       → getUserMetrics
+ * - GET /analytics/top-products → getTopProducts
+ * - GET /analytics/time-series → getTimeSeries
+ * - GET /analytics/orders/period → getOrderMetricsForPeriod
+ */
+
+import type { AnalyticsService } from '../services/analytics.service.js';
+import type {
+  TimeGranularity,
+  DashboardData,
+  OrderMetricSummary,
+  UserMetricSummary,
+  TopProduct,
+  TimeSeriesDataPoint,
+} from '../models/analytics.js';
+import type {
+  RouteRequest,
+  RouteResponse,
+  RouteHandler,
+  ErrorBody,
+} from './types.js';
+
+const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];
+
+function isValidGranularity(value: string): value is TimeGranularity {
+  return VALID_GRANULARITIES.includes(value as TimeGranularity);
+}
+
+function parseDate(value: string | undefined): Date | undefined {
+  if (value === undefined) return undefined;
+  const date = new Date(value);
+  if (isNaN(date.getTime())) return undefined;
+  return date;
+}
+
+function parseDateStrict(
+  value: string | undefined,
+  paramName: string,
+): { date: Date } | { error: string } {
+  if (value === undefined) {
+    return { error: `Missing required parameter: ${paramName}` };
+  }
+  const date = new Date(value);
+  if (isNaN(date.getTime())) {
+    return { error: `Invalid date for ${paramName}: ${value}` };
+  }
+  return { date };
+}
+
+function parsePositiveInt(
+  value: string | undefined,
+  defaultValue: number,
+): number | null {
+  if (value === undefined) return defaultValue;
+  const n = parseInt(value, 10);
+  if (isNaN(n) || n < 1) return null;
+  return n;
+}
+
+export class AnalyticsRoutes {
+  constructor(private analyticsService: AnalyticsService) {}
+
+  /**
+   * GET /analytics/dashboard
+   *
+   * Query params:
+   *   granularity?: 'hour' | 'day' | 'week' | 'month' (default: 'day')
+   *   startDate?: ISO date string
+   *   endDate?: ISO date string
+   *   topProductsLimit?: positive integer (default: 10)
+   */
+  getDashboard: RouteHandler<DashboardData | ErrorBody> = (
+    req: RouteRequest,
+  ): RouteResponse<DashboardData | ErrorBody> => {
+    const { granularity: granularityParam, startDate: startParam, endDate: endParam, topProductsLimit: limitParam } = req.query;
+
+    const granularity = granularityParam ?? 'day';
+    if (!isValidGranularity(granularity)) {
+      return {
+        status: 400,
+        data: { error: `Invalid granularity: ${granularity}. Must be one of: ${VALID_GRANULARITIES.join(', ')}` },
+      };
+    }
+
+    const startDate = parseDate(startParam);
+    if (startParam !== undefined && startDate === undefined) {
+      return { status: 400, data: { error: `Invalid startDate: ${startParam}` } };
+    }
+
+    const endDate = parseDate(endParam);
+    if (endParam !== undefined && endDate === undefined) {
+      return { status: 400, data: { error: `Invalid endDate: ${endParam}` } };
+    }
+
+    const topProductsLimit = parsePositiveInt(limitParam, 10);
+    if (topProductsLimit === null) {
+      return { status: 400, data: { error: `Invalid topProductsLimit: ${limitParam}. Must be a positive integer` } };
+    }
+
+    const data = this.analyticsService.getDashboardData(
+      granularity,
+      startDate,
+      endDate,
+      topProductsLimit,
+    );
+
+    return { status: 200, data };
+  };
+
+  /**
+   * GET /analytics/orders
+   *
+   * No parameters — returns order metric summary.
+   */
+  getOrderMetrics: RouteHandler<OrderMetricSummary> = (): RouteResponse<OrderMetricSummary> => {
+    const data = this.analyticsService.getOrderMetrics();
+    return { status: 200, data };
+  };
+
+  /**
+   * GET /analytics/users
+   *
+   * No parameters — returns user metric summary.
+   */
+  getUserMetrics: RouteHandler<UserMetricSummary> = (): RouteResponse<UserMetricSummary> => {
+    const data = this.analyticsService.getUserMetrics();
+    return { status: 200, data };
+  };
+
+  /**
+   * GET /analytics/top-products
+   *
+   * Query params:
+   *   limit?: positive integer (default: 10)
+   */
+  getTopProducts: RouteHandler<TopProduct[] | ErrorBody> = (
+    req: RouteRequest,
+  ): RouteResponse<TopProduct[] | ErrorBody> => {
+    const limit = parsePositiveInt(req.query.limit, 10);
+    if (limit === null) {
+      return { status: 400, data: { error: `Invalid limit: ${req.query.limit}. Must be a positive integer` } };
+    }
+
+    const data = this.analyticsService.getTopProducts(limit);
+    return { status: 200, data };
+  };
+
+  /**
+   * GET /analytics/time-series
+   *
+   * Query params:
+   *   granularity?: 'hour' | 'day' | 'week' | 'month' (default: 'day')
+   *   startDate?: ISO date string
+   *   endDate?: ISO date string
+   */
+  getTimeSeries: RouteHandler<TimeSeriesDataPoint[] | ErrorBody> = (
+    req: RouteRequest,
+  ): RouteResponse<TimeSeriesDataPoint[] | ErrorBody> => {
+    const { granularity: granularityParam, startDate: startParam, endDate: endParam } = req.query;
+
+    const granularity = granularityParam ?? 'day';
+    if (!isValidGranularity(granularity)) {
+      return {
+        status: 400,
+        data: { error: `Invalid granularity: ${granularity}. Must be one of: ${VALID_GRANULARITIES.join(', ')}` },
+      };
+    }
+
+    const startDate = parseDate(startParam);
+    if (startParam !== undefined && startDate === undefined) {
+      return { status: 400, data: { error: `Invalid startDate: ${startParam}` } };
+    }
+
+    const endDate = parseDate(endParam);
+    if (endParam !== undefined && endDate === undefined) {
+      return { status: 400, data: { error: `Invalid endDate: ${endParam}` } };
+    }
+
+    const data = this.analyticsService.aggregateTimeSeries(
+      granularity,
+      startDate,
+      endDate,
+    );
+
+    return { status: 200, data };
+  };
+
+  /**
+   * GET /analytics/orders/period
+   *
+   * Query params:
+   *   startDate: ISO date string (required)
+   *   endDate: ISO date string (required)
+   */
+  getOrderMetricsForPeriod: RouteHandler<OrderMetricSummary | ErrorBody> = (
+    req: RouteRequest,
+  ): RouteResponse<OrderMetricSummary | ErrorBody> => {
+    const startResult = parseDateStrict(req.query.startDate, 'startDate');
+    if ('error' in startResult) {
+      return { status: 400, data: { error: startResult.error } };
+    }
+
+    const endResult = parseDateStrict(req.query.endDate, 'endDate');
+    if ('error' in endResult) {
+      return { status: 400, data: { error: endResult.error } };
+    }
+
+    const data = this.analyticsService.getOrderMetricsForPeriod(
+      startResult.date,
+      endResult.date,
+    );
+
+    return { status: 200, data };
+  };
+}

