+
+    it('respects custom limit', () => {
+      seedOrder({ id: 'o1', items: [{ productId: 'p1', name: 'A', quantity: 1, unitPrice: 50 }], total: 50 });
+      seedOrder({ id: 'o2', items: [{ productId: 'p2', name: 'B', quantity: 1, unitPrice: 30 }], total: 30 });
+      seedOrder({ id: 'o3', items: [{ productId: 'p3', name: 'C', quantity: 1, unitPrice: 10 }], total: 10 });
+      const res = routes.getTopProducts(makeRequest({ limit: '2' }));
+      expect(res.status).toBe(200);
+      expect((res.data as any[]).length).toBe(2);
+    });
+
+    it('rejects invalid limit', () => {
+      const res = routes.getTopProducts(makeRequest({ limit: '-1' }));
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Invalid limit');
+    });
+
+    it('rejects non-numeric limit', () => {
+      const res = routes.getTopProducts(makeRequest({ limit: 'foo' }));
+      expect(res.status).toBe(400);
+    });
+  });
+
+  describe('getTimeSeries', () => {
+    it('returns 200 with time series data', () => {
+      seedOrder();
+      const res = routes.getTimeSeries(makeRequest({ granularity: 'day' }));
+      expect(res.status).toBe(200);
+      expect(Array.isArray(res.data)).toBe(true);
+    });
+
+    it('defaults to day granularity', () => {
+      seedOrder();
+      const res = routes.getTimeSeries(makeRequest());
+      expect(res.status).toBe(200);
+      expect(Array.isArray(res.data)).toBe(true);
+    });
+
+    it('rejects invalid granularity', () => {
+      const res = routes.getTimeSeries(makeRequest({ granularity: 'quarter' }));
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Invalid granularity');
+    });
+
+    it('rejects invalid startDate', () => {
+      const res = routes.getTimeSeries(makeRequest({ startDate: 'nope' }));
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Invalid startDate');
+    });
+
+    it('rejects invalid endDate', () => {
+      const res = routes.getTimeSeries(makeRequest({ endDate: 'nope' }));
+      expect(res.status).toBe(400);
+    });
+
+    it('filters by date range', () => {
+      seedOrder({ id: 'o1', createdAt: new Date('2025-01-01'), total: 10 });
+      seedOrder({ id: 'o2', createdAt: new Date('2025-06-01'), total: 20 });
+      const res = routes.getTimeSeries(
+        makeRequest({ startDate: '2025-05-01', endDate: '2025-07-01' }),
+      );
+      expect(res.status).toBe(200);
+      const series = res.data as any[];
+      expect(series.length).toBe(1);
+    });
+  });
+
+  describe('getOrderMetricsForPeriod', () => {
+    it('returns 200 with metrics for a date range', () => {
+      seedOrder({ id: 'o1', createdAt: new Date('2025-03-15'), total: 50 });
+      const res = routes.getOrderMetricsForPeriod(
+        makeRequest({ startDate: '2025-03-01', endDate: '2025-03-31' }),
+      );
+      expect(res.status).toBe(200);
+      expect((res.data as any).totalOrders).toBe(1);
+    });
+
+    it('returns 400 when startDate is missing', () => {
+      const res = routes.getOrderMetricsForPeriod(
+        makeRequest({ endDate: '2025-03-31' }),
+      );
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Missing required parameter: startDate');
+    });
+
+    it('returns 400 when endDate is missing', () => {
+      const res = routes.getOrderMetricsForPeriod(
+        makeRequest({ startDate: '2025-03-01' }),
+      );
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Missing required parameter: endDate');
+    });
+
+    it('returns 400 for invalid startDate', () => {
+      const res = routes.getOrderMetricsForPeriod(
+        makeRequest({ startDate: 'bad', endDate: '2025-03-31' }),
+      );
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Invalid date for startDate');
+    });
+
+    it('returns 400 for invalid endDate', () => {
+      const res = routes.getOrderMetricsForPeriod(
+        makeRequest({ startDate: '2025-03-01', endDate: 'bad' }),
+      );
+      expect(res.status).toBe(400);
+      expect((res.data as any).error).toContain('Invalid date for endDate');
+    });
+
+    it('returns empty metrics when no orders in range', () => {
+      seedOrder({ id: 'o1', createdAt: new Date('2025-01-01'), total: 50 });
+      const res = routes.getOrderMetricsForPeriod(
+        makeRequest({ startDate: '2025-06-01', endDate: '2025-06-30' }),
+      );
+      expect(res.status).toBe(200);
+      expect((res.data as any).totalOrders).toBe(0);
+    });
+  });
+});

