import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { AnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

function makeRequest(
  query: Record<string, string | undefined> = {},
  params: Record<string, string | undefined> = {},
): RouteRequest {
  return { query, params };
}

describe('AnalyticsRoutes', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;
  let routes: AnalyticsRoutes;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = new AnalyticsRoutes(service);
  });

  function seedUser(overrides: Partial<User> = {}): User {
    const user: User = {
      id: 'user-001',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'admin',
      createdAt: new Date('2025-01-01'),
      updatedAt: new Date('2025-01-01'),
      ...overrides,
    };
    userRepo.save(user);
    return user;
  }

  function seedOrder(overrides: Partial<Order> = {}): Order {
    const order: Order = {
      id: 'order-001',
      userId: 'user-001',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date('2025-03-15'),
      updatedAt: new Date('2025-03-15'),
      ...overrides,
    };
    orderRepo.save(order);
    return order;
  }

  describe('getDashboard', () => {
    it('returns 200 with dashboard data using defaults', () => {
      seedUser();
      seedOrder();
      const res = routes.getDashboard(makeRequest());
      expect(res.status).toBe(200);
      const data = res.data as any;
      expect(data.orderMetrics).toBeDefined();
      expect(data.userMetrics).toBeDefined();
      expect(data.timeSeries).toBeDefined();
      expect(data.topProducts).toBeDefined();
      expect(data.generatedAt).toBeDefined();
    });

    it('accepts valid granularity', () => {
      const res = routes.getDashboard(makeRequest({ granularity: 'month' }));
      expect(res.status).toBe(200);
    });

    it('rejects invalid granularity', () => {
      const res = routes.getDashboard(makeRequest({ granularity: 'year' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid granularity');
    });

    it('accepts valid date range', () => {
      seedUser();
      seedOrder();
      const res = routes.getDashboard(
        makeRequest({ startDate: '2025-01-01', endDate: '2025-12-31' }),
      );
      expect(res.status).toBe(200);
    });

    it('rejects invalid startDate', () => {
      const res = routes.getDashboard(makeRequest({ startDate: 'not-a-date' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid startDate');
    });

    it('rejects invalid endDate', () => {
      const res = routes.getDashboard(makeRequest({ endDate: 'bad' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid endDate');
    });

    it('accepts valid topProductsLimit', () => {
      const res = routes.getDashboard(makeRequest({ topProductsLimit: '5' }));
      expect(res.status).toBe(200);
    });

    it('rejects non-positive topProductsLimit', () => {
      const res = routes.getDashboard(makeRequest({ topProductsLimit: '0' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid topProductsLimit');
    });

    it('rejects non-numeric topProductsLimit', () => {
      const res = routes.getDashboard(makeRequest({ topProductsLimit: 'abc' }));
      expect(res.status).toBe(400);
    });
  });

  describe('getOrderMetrics', () => {
    it('returns 200 with order metrics', () => {
      seedOrder();
      const res = routes.getOrderMetrics(makeRequest());
      expect(res.status).toBe(200);
      const data = res.data as any;
      expect(data.totalOrders).toBe(1);
      expect(data.totalRevenue).toBe(20);
      expect(data.averageOrderValue).toBe(20);
      expect(data.ordersByStatus).toBeDefined();
    });

    it('returns zero metrics when no orders exist', () => {
      const res = routes.getOrderMetrics(makeRequest());
      expect(res.status).toBe(200);
      expect((res.data as any).totalOrders).toBe(0);
    });
  });

  describe('getUserMetrics', () => {
    it('returns 200 with user metrics', () => {
      seedUser();
      seedUser({ id: 'user-002', email: 'bob@example.com', name: 'Bob', role: 'member' });
      const res = routes.getUserMetrics(makeRequest());
      expect(res.status).toBe(200);
      const data = res.data as any;
      expect(data.totalUsers).toBe(2);
      expect(data.usersByRole.admin).toBe(1);
      expect(data.usersByRole.member).toBe(1);
    });

    it('returns zero metrics when no users exist', () => {
      const res = routes.getUserMetrics(makeRequest());
      expect(res.status).toBe(200);
      expect((res.data as any).totalUsers).toBe(0);
    });
  });

  describe('getTopProducts', () => {
    it('returns 200 with top products using default limit', () => {
      seedOrder();
      const res = routes.getTopProducts(makeRequest());
      expect(res.status).toBe(200);
      expect(Array.isArray(res.data)).toBe(true);
      expect((res.data as any[])[0].productId).toBe('p1');
    });

    it('respects custom limit', () => {
      seedOrder({ id: 'o1', items: [{ productId: 'p1', name: 'A', quantity: 1, unitPrice: 50 }], total: 50 });
      seedOrder({ id: 'o2', items: [{ productId: 'p2', name: 'B', quantity: 1, unitPrice: 30 }], total: 30 });
      seedOrder({ id: 'o3', items: [{ productId: 'p3', name: 'C', quantity: 1, unitPrice: 10 }], total: 10 });
      const res = routes.getTopProducts(makeRequest({ limit: '2' }));
      expect(res.status).toBe(200);
      expect((res.data as any[]).length).toBe(2);
    });

    it('rejects invalid limit', () => {
      const res = routes.getTopProducts(makeRequest({ limit: '-1' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid limit');
    });

    it('rejects non-numeric limit', () => {
      const res = routes.getTopProducts(makeRequest({ limit: 'foo' }));
      expect(res.status).toBe(400);
    });
  });

  describe('getTimeSeries', () => {
    it('returns 200 with time series data', () => {
      seedOrder();
      const res = routes.getTimeSeries(makeRequest({ granularity: 'day' }));
      expect(res.status).toBe(200);
      expect(Array.isArray(res.data)).toBe(true);
    });

    it('defaults to day granularity', () => {
      seedOrder();
      const res = routes.getTimeSeries(makeRequest());
      expect(res.status).toBe(200);
      expect(Array.isArray(res.data)).toBe(true);
    });

    it('rejects invalid granularity', () => {
      const res = routes.getTimeSeries(makeRequest({ granularity: 'quarter' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid granularity');
    });

    it('rejects invalid startDate', () => {
      const res = routes.getTimeSeries(makeRequest({ startDate: 'nope' }));
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid startDate');
    });

    it('rejects invalid endDate', () => {
      const res = routes.getTimeSeries(makeRequest({ endDate: 'nope' }));
      expect(res.status).toBe(400);
    });

    it('filters by date range', () => {
      seedOrder({ id: 'o1', createdAt: new Date('2025-01-01'), total: 10 });
      seedOrder({ id: 'o2', createdAt: new Date('2025-06-01'), total: 20 });
      const res = routes.getTimeSeries(
        makeRequest({ startDate: '2025-05-01', endDate: '2025-07-01' }),
      );
      expect(res.status).toBe(200);
      const series = res.data as any[];
      expect(series.length).toBe(1);
    });
  });

  describe('getOrderMetricsForPeriod', () => {
    it('returns 200 with metrics for a date range', () => {
      seedOrder({ id: 'o1', createdAt: new Date('2025-03-15'), total: 50 });
      const res = routes.getOrderMetricsForPeriod(
        makeRequest({ startDate: '2025-03-01', endDate: '2025-03-31' }),
      );
      expect(res.status).toBe(200);
      expect((res.data as any).totalOrders).toBe(1);
    });

    it('returns 400 when startDate is missing', () => {
      const res = routes.getOrderMetricsForPeriod(
        makeRequest({ endDate: '2025-03-31' }),
      );
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Missing required parameter: startDate');
    });

    it('returns 400 when endDate is missing', () => {
      const res = routes.getOrderMetricsForPeriod(
        makeRequest({ startDate: '2025-03-01' }),
      );
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Missing required parameter: endDate');
    });

    it('returns 400 for invalid startDate', () => {
      const res = routes.getOrderMetricsForPeriod(
        makeRequest({ startDate: 'bad', endDate: '2025-03-31' }),
      );
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid date for startDate');
    });

    it('returns 400 for invalid endDate', () => {
      const res = routes.getOrderMetricsForPeriod(
        makeRequest({ startDate: '2025-03-01', endDate: 'bad' }),
      );
      expect(res.status).toBe(400);
      expect((res.data as any).error).toContain('Invalid date for endDate');
    });

    it('returns empty metrics when no orders in range', () => {
      seedOrder({ id: 'o1', createdAt: new Date('2025-01-01'), total: 50 });
      const res = routes.getOrderMetricsForPeriod(
        makeRequest({ startDate: '2025-06-01', endDate: '2025-06-30' }),
      );
      expect(res.status).toBe(200);
      expect((res.data as any).totalOrders).toBe(0);
    });
  });
});
